import android.content.Context;
import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.ResponseBody;

public class HttpClient {

    private OkHttpClient okHttpClient;

    public HttpClient() {
        this.okHttpClient = new OkHttpClient();
    }

    public String executeGet(String urlString) throws IOException {
        URL url = new URL(urlString);
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");
        connection.connect();

        BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
        StringBuilder response = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            response.append(line);
        }
        reader.close();
        return response.toString();
    }

    public String executePost(String urlString, String jsonInputString) throws IOException {
        HttpURLConnection connection = (HttpURLConnection) new URL(urlString).openConnection();
        connection.setRequestMethod("POST");
        connection.setRequestProperty("Content-Type", "application/json; utf-8");
        connection.setRequestProperty("Accept", "application/json");
        connection.setDoOutput(true);
        
        try (OutputStream os = connection.getOutputStream()) {
            byte[] input = jsonInputString.getBytes("utf-8");
            os.write(input, 0, input.length);
        }

        BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
        StringBuilder response = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            response.append(line);
        }
        reader.close();
        return response.toString();
    }

    public String okHttpGet(String urlString) throws IOException {
        Request request = new Request.Builder()
                .url(urlString)
                .build();
        
        Response response = okHttpClient.newCall(request).execute();
        ResponseBody responseBody = response.body();
        return responseBody != null ? responseBody.string() : null;
    }

    public String okHttpPost(String urlString, String jsonInputString) throws IOException {
        Request request = new Request.Builder()
                .url(urlString)
                .post(okhttp3.RequestBody.create(
                        jsonInputString,
                        okhttp3.MediaType.parse("application/json; charset=utf-8")))
                .build();
        
        Response response = okHttpClient.newCall(request).execute();
        ResponseBody responseBody = response.body();
        return responseBody != null ? responseBody.string() : null;
    }
}